 1→document.addEventListener("DOMContentLoaded", async () => {
 2→  const form = document.getElementById("capture-form");
 3→  const urlInput = document.getElementById("url");
 4→  const titleInput = document.getElementById("title");
 5→  const selectionInput = document.getElementById("selection");
 6→  const tagsInput = document.getElementById("tags");
 7→  const sensitivitySelect = document.getElementById("sensitivity");
 8→  const saveBtn = document.getElementById("save-btn");
 9→  const statusDiv = document.getElementById("status");
10→  const notConfigured = document.getElementById("not-configured");
11→  const openOptions = document.getElementById("open-options");
12→
13→  // Check if configured
14→  const { apiUrl, jwtToken } = await chrome.storage.local.get([
15→    "apiUrl",
16→    "jwtToken",
17→  ]);
18→
19→  if (!apiUrl || !jwtToken) {
20→    notConfigured.hidden = false;
21→    form.hidden = true;
22→    openOptions.addEventListener("click", (e) => {
23→      e.preventDefault();
24→      chrome.runtime.openOptionsPage();
25→    });
26→    return;
27→  }
28→
29→  // Get current tab info
30→  const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });
31→  if (tab) {
32→    urlInput.value = tab.url || "";
33→    titleInput.value = tab.title || "";
34→
35→    // Try to get selected text from the page
36→    try {
37→      const results = await chrome.scripting.executeScript({
38→        target: { tabId: tab.id },
39→        files: ["content/content.js"],
40→      });
41→      if (results && results[0] && results[0].result) {
42→        selectionInput.value = results[0].result;
43→      }
44→    } catch {
45→      // Content script injection may fail on chrome:// or extension pages
46→    }
47→  }
48→
49→  form.addEventListener("submit", async (e) => {
50→    e.preventDefault();
51→    saveBtn.disabled = true;
52→    saveBtn.textContent = "Saving...";
53→    statusDiv.hidden = true;
54→
55→    const rawTags = tagsInput.value
56→      .split(",")
57→      .map((t) => t.trim())
58→      .filter(Boolean);
59→
60→    const input = {
61→      url: urlInput.value,
62→      title: titleInput.value || null,
63→      selection: selectionInput.value || null,
64→      tags: rawTags.length > 0 ? rawTags : null,
65→      sensitivity: sensitivitySelect.value,
66→    };
67→
68→    try {
69→      const response = await chrome.runtime.sendMessage({
70→        action: "captureBookmark",
71→        input,
72→      });
73→
74→      if (response.success) {
75→        showStatus("Bookmark saved!", "success");
76→        saveBtn.textContent = "Saved";
77→      } else {
78→        showStatus(response.error || "Failed to save bookmark", "error");
79→        saveBtn.disabled = false;
80→        saveBtn.textContent = "Save Bookmark";
81→      }
82→    } catch (err) {
83→      showStatus("Extension error: " + err.message, "error");
84→      saveBtn.disabled = false;
85→      saveBtn.textContent = "Save Bookmark";
86→    }
87→  });
88→
89→  function showStatus(message, type) {
90→    statusDiv.textContent = message;
91→    statusDiv.className = type;
92→    statusDiv.hidden = false;
93→  }
94→});
