 1→const CAPTURE_MUTATION = `
 2→  mutation CaptureBookmark($input: BookmarkInput!) {
 3→    captureBookmark(input: $input) {
 4→      id
 5→      status
 6→      title
 7→      tags
 8→    }
 9→  }
10→`;
11→
12→chrome.runtime.onMessage.addListener((message, _sender, sendResponse) => {
13→  if (message.action === "captureBookmark") {
14→    handleCapture(message.input).then(sendResponse);
15→    return true; // keep message channel open for async response
16→  }
17→});
18→
19→async function handleCapture(input) {
20→  try {
21→    const { apiUrl, jwtToken } = await chrome.storage.local.get([
22→      "apiUrl",
23→      "jwtToken",
24→    ]);
25→
26→    if (!apiUrl || !jwtToken) {
27→      return { success: false, error: "Extension not configured" };
28→    }
29→
30→    const graphqlUrl = apiUrl.replace(/\/+$/, "") + "/graphql";
31→
32→    const res = await fetch(graphqlUrl, {
33→      method: "POST",
34→      headers: {
35→        "Content-Type": "application/json",
36→        Authorization: "Bearer " + jwtToken,
37→      },
38→      body: JSON.stringify({
39→        query: CAPTURE_MUTATION,
40→        variables: { input },
41→      }),
42→    });
43→
44→    if (!res.ok) {
45→      const text = await res.text();
46→      return { success: false, error: `HTTP ${res.status}: ${text}` };
47→    }
48→
49→    const json = await res.json();
50→
51→    if (json.errors && json.errors.length > 0) {
52→      return { success: false, error: json.errors[0].message };
53→    }
54→
55→    return { success: true, data: json.data.captureBookmark };
56→  } catch (err) {
57→    return { success: false, error: err.message };
58→  }
59→}
